sql:
SELECT crime_name, severity_level
FROM crimes
WHERE crime_id > 5;

external_knowledge:
- 'last month of spring' refers to April 2023;
- 'checked for' means the records were accessed through a 'view';
- 'State' is a specific jurisdiction.

- 'Spring' metaphorically refers to the year 2020;
- 'Summer' stands for the year 2022;
- The metaphor of a 'garden' is used to represent the diverse categories of crime, with different types of plants symbolizing different categories of crimes;
- 'Leaves' are used to symbolize the number of cases reported, thus 'counting the leaves' translates to counting the number of cases reported;
- Each season represents a year, allowing a comparative view of 'plant growth' (crime cases) over the years 2020, 2021, and 2022.

sql:
SELECT trend_details, trend_type, trend_impact
FROM crime_trends
WHERE jurisdiction_id = 1;

SELECT report_details, report_date
FROM crime_reporting
WHERE reporter_id = 1 AND jurisdiction_id = 1;

SELECT COUNT(crime_id)
FROM crime_reporting
WHERE jurisdiction_id = 1;

SELECT crimes.crime_name, crime_statistics.total_persons_under_trial
FROM crimes
INNER JOIN crime_statistics ON crimes.crime_id = crime_statistics.crime_id;

SELECT jurisdiction_name, population, area
FROM jurisdictions
WHERE jurisdiction_id = 1;

SELECT user_id
FROM agency_users
WHERE role = 'analyst' AND department = 'Data Analysis';

SELECT report_id, crime_id, jurisdiction_id
FROM crime_reporting
WHERE reporter_id IN (SELECT user_id FROM agency_users);
